#include "engine/orb/messages/InvokeMethodMessage.h"


PobShipObjectAdapter::PobShipObjectAdapter(PobShipObject* obj) : ShipObjectAdapter(obj) {
}

void PobShipObjectAdapter::invokeMethod(uint32 methid, DistributedMethod* inv) {
	DOBMessage* resp = inv->getInvocationMessage();

	switch (methid) {
	case RPC_NOTIFYLOADFROMDATABASE__:
		{
			
			notifyLoadFromDatabase();
			
		}
		break;
	case RPC_CREATECHILDOBJECTS__:
		{
			
			createChildObjects();
			
		}
		break;
	case RPC_DESTROYOBJECTFROMDATABASE__BOOL_:
		{
			bool destroyContainedObjects = inv->getBooleanParameter();
			
			destroyObjectFromDatabase(destroyContainedObjects);
			
		}
		break;
	case RPC_NOTIFYINSERTTOZONE__ZONE_:
		{
			Zone* zone = static_cast<Zone*>(inv->getObjectParameter());
			
			notifyInsertToZone(zone);
			
		}
		break;
	case RPC_NOTIFYOBJECTINSERTEDTOCHILD__SCENEOBJECT_SCENEOBJECT_SCENEOBJECT_:
		{
			SceneObject* object = static_cast<SceneObject*>(inv->getObjectParameter());
			SceneObject* child = static_cast<SceneObject*>(inv->getObjectParameter());
			SceneObject* oldParent = static_cast<SceneObject*>(inv->getObjectParameter());
			
			int _m_res = notifyObjectInsertedToChild(object, child, oldParent);
			resp->insertSignedInt(_m_res);
		}
		break;
	case RPC_NOTIFYOBJECTREMOVEDFROMCHILD__SCENEOBJECT_SCENEOBJECT_:
		{
			SceneObject* object = static_cast<SceneObject*>(inv->getObjectParameter());
			SceneObject* child = static_cast<SceneObject*>(inv->getObjectParameter());
			
			int _m_res = notifyObjectRemovedFromChild(object, child);
			resp->insertSignedInt(_m_res);
		}
		break;
	case RPC_ONENTER__CREATUREOBJECT_LONG_:
		{
			CreatureObject* player = static_cast<CreatureObject*>(inv->getObjectParameter());
			unsigned long long skipCellID = inv->getUnsignedLongParameter();
			
			onEnter(player, skipCellID);
			
		}
		break;
	case RPC_SENDTO__SCENEOBJECT_BOOL_BOOL_:
		{
			SceneObject* player = static_cast<SceneObject*>(inv->getObjectParameter());
			bool doClose = inv->getBooleanParameter();
			bool forceLoadContainer = inv->getBooleanParameter();
			
			sendTo(player, doClose, forceLoadContainer);
			
		}
		break;
	case RPC_SENDCONTAINEROBJECTSTO__SCENEOBJECT_BOOL_:
		{
			SceneObject* player = static_cast<SceneObject*>(inv->getObjectParameter());
			bool forceLoad = inv->getBooleanParameter();
			
			sendContainerObjectsTo(player, forceLoad);
			
		}
		break;
	case RPC_UPDATECELLPERMISSIONSTO__CREATUREOBJECT_:
		{
			CreatureObject* creature = static_cast<CreatureObject*>(inv->getObjectParameter());
			
			updateCellPermissionsTo(creature);
			
		}
		break;
	case RPC_ISONADMINLIST__CREATUREOBJECT_:
		{
			CreatureObject* player = static_cast<CreatureObject*>(inv->getObjectParameter());
			
			bool _m_res = isOnAdminList(player);
			resp->insertBoolean(_m_res);
		}
		break;
	case RPC_ISONPERMISSIONLIST__STRING_CREATUREOBJECT_:
		{
			 String listName; inv->getAsciiParameter(listName);
			CreatureObject* player = static_cast<CreatureObject*>(inv->getObjectParameter());
			
			bool _m_res = isOnPermissionList(listName, player);
			resp->insertBoolean(_m_res);
		}
		break;
	case RPC_ISONADMINLIST__LONG_:
		{
			unsigned const long long objectID = inv->getUnsignedLongParameter();
			
			bool _m_res = isOnAdminList(objectID);
			resp->insertBoolean(_m_res);
		}
		break;
	case RPC_TOGGLEPLASMAALARMS__:
		{
			
			togglePlasmaAlarms();
			
		}
		break;
	case RPC_TRIGGERINTERIORDAMAGE__INT_FLOAT_:
		{
			int hitType = inv->getSignedIntParameter();
			float damageVar = inv->getFloatParameter();
			
			triggerInteriorDamage(hitType, damageVar);
			
		}
		break;
	case RPC_DOINTERIOREFFECT__ZONE_CELLOBJECT_STRING_INT_INT_VECTOR_VECTOR_INT_:
		{
			Zone* zone = static_cast<Zone*>(inv->getObjectParameter());
			CellObject* cell = static_cast<CellObject*>(inv->getObjectParameter());
			String randomCell; inv->getAsciiParameter(randomCell);
			int count = inv->getSignedIntParameter();
			int chance = inv->getSignedIntParameter();
			Vector<String> clientEffects = inv->getDereferencedSerializableParameter<Vector<String> >();
			Vector<float> damageEffects = inv->getDereferencedSerializableParameter<Vector<float> >();
			int conduitChance = inv->getSignedIntParameter();
			
			doInteriorEffect(zone, cell, randomCell, count, chance, clientEffects, damageEffects, conduitChance);
			
		}
		break;
	case RPC_TRIGGERCELLDAMAGEOVERTIME__:
		{
			
			bool _m_res = triggerCellDamageOverTime();
			resp->insertBoolean(_m_res);
		}
		break;
	case RPC_CHECKPLASMACONDUITS__:
		{
			
			checkPlasmaConduits();
			
		}
		break;
	case RPC_SETCOMPONENTDAMAGEVARIABLE__INT_:
		{
			unsigned int componentSlot = inv->getUnsignedIntParameter();
			
			setComponentDamageVariable(componentSlot);
			
		}
		break;
	case RPC_APPLYPOBCOMPONENTDOT__:
		{
			
			applyPobComponentDot();
			
		}
		break;
	case RPC_ISPOBSHIP__:
		{
			
			bool _m_res = isPobShip();
			resp->insertBoolean(_m_res);
		}
		break;
	case RPC_GETCURRENTNUMBEROFPLAYERITEMS__:
		{
			
			int _m_res = getCurrentNumberOfPlayerItems();
			resp->insertSignedInt(_m_res);
		}
		break;
	case RPC_GETMAXIMUMNUMBEROFPLAYERITEMS__:
		{
			
			unsigned int _m_res = getMaximumNumberOfPlayerItems();
			resp->insertInt(_m_res);
		}
		break;
	case RPC_DESTROYALLPLAYERITEMS__:
		{
			
			destroyAllPlayerItems();
			
		}
		break;
	case RPC_AWARDLOOTITEMS__SHIPAIAGENT_INT_:
		{
			ShipAiAgent* destructedShip = static_cast<ShipAiAgent*>(inv->getObjectParameter());
			int payout = inv->getSignedIntParameter();
			
			awardLootItems(destructedShip, payout);
			
		}
		break;
	case RPC_GETCELL__INT_:
		{
			int idx = inv->getSignedIntParameter();
			
			DistributedObject* _m_res = getCell(idx);
			resp->insertLong(_m_res == NULL ? 0 : _m_res->_getObjectID());
		}
		break;
	case RPC_GETCELL__STRING_:
		{
			 String name; inv->getAsciiParameter(name);
			
			DistributedObject* _m_res = getCell(name);
			resp->insertLong(_m_res == NULL ? 0 : _m_res->_getObjectID());
		}
		break;
	case RPC_GETTOTALCELLNUMBER__:
		{
			
			int _m_res = getTotalCellNumber();
			resp->insertSignedInt(_m_res);
		}
		break;
	case RPC_SENDPERMISSIONLISTTO__CREATUREOBJECT_STRING_:
		{
			CreatureObject* creature = static_cast<CreatureObject*>(inv->getObjectParameter());
			 String listName; inv->getAsciiParameter(listName);
			
			sendPermissionListTo(creature, listName);
			
		}
		break;
	case RPC_GRANTPERMISSION__STRING_LONG_:
		{
			 String listName; inv->getAsciiParameter(listName);
			unsigned const long long objectID = inv->getUnsignedLongParameter();
			
			int _m_res = grantPermission(listName, objectID);
			resp->insertSignedInt(_m_res);
		}
		break;
	case RPC_REVOKEPERMISSION__STRING_LONG_:
		{
			 String listName; inv->getAsciiParameter(listName);
			unsigned const long long objectID = inv->getUnsignedLongParameter();
			
			int _m_res = revokePermission(listName, objectID);
			resp->insertSignedInt(_m_res);
		}
		break;
	case RPC_TOGGLEPERMISSION__STRING_LONG_:
		{
			 String listName; inv->getAsciiParameter(listName);
			unsigned const long long objectID = inv->getUnsignedLongParameter();
			
			int _m_res = togglePermission(listName, objectID);
			resp->insertSignedInt(_m_res);
		}
		break;
	case RPC_HASPERMISSIONLIST__STRING_:
		{
			 String listName; inv->getAsciiParameter(listName);
			
			bool _m_res = hasPermissionList(listName);
			resp->insertBoolean(_m_res);
		}
		break;
	case RPC_ISPERMISSIONLISTFULL__STRING_:
		{
			 String listName; inv->getAsciiParameter(listName);
			
			bool _m_res = isPermissionListFull(listName);
			resp->insertBoolean(_m_res);
		}
		break;
	case RPC_ISONPERMISSIONLIST__STRING_LONG_:
		{
			 String listName; inv->getAsciiParameter(listName);
			unsigned const long long objectID = inv->getUnsignedLongParameter();
			
			bool _m_res = isOnPermissionList(listName, objectID);
			resp->insertBoolean(_m_res);
		}
		break;
	case RPC_GETTOTALPLASMAALARMS__:
		{
			
			int _m_res = getTotalPlasmaAlarms();
			resp->insertSignedInt(_m_res);
		}
		break;
	case RPC_GETPLASMAALARMS__INT_:
		{
			int idx = inv->getSignedIntParameter();
			
			unsigned long long _m_res = getPlasmaAlarms(idx);
			resp->insertLong(_m_res);
		}
		break;
	case RPC_ADDDAMAGEDINTERIORCOMPONENT__LONG_INT_:
		{
			unsigned long long interiorComponentID = inv->getUnsignedLongParameter();
			int type = inv->getSignedIntParameter();
			
			addDamagedInteriorComponent(interiorComponentID, type);
			
		}
		break;
	case RPC_REMOVEDAMAGEDINTERIORCOMPONENT__LONG_:
		{
			unsigned long long interiorComponentID = inv->getUnsignedLongParameter();
			
			removeDamagedInteriorComponent(interiorComponentID);
			
		}
		break;
	case RPC_HASACTIVEPLASMALEAKS__:
		{
			
			bool _m_res = hasActivePlasmaLeaks();
			resp->insertBoolean(_m_res);
		}
		break;
	case RPC_REMOVEALLPLAYERSFROMSHIP__:
		{
			
			removeAllPlayersFromShip();
			
		}
		break;
	default:
		ShipObjectAdapter::invokeMethod(methid, inv);
	}
}

