bool PobShipObjectPOD::readObjectMember(ObjectInputStream* stream, const uint32& nameHashCode) {
	if (ShipObjectPOD::readObjectMember(stream, nameHashCode))
		return true;

	switch(nameHashCode) {
	case 0x3947fdd9: //PobShipObject.cellNameMap
		{
			VectorMap<String, ManagedReference<CellObjectPOD* > > _mncellNameMap;
			TypeInfo<VectorMap<String, ManagedReference<CellObjectPOD* > > >::parseFromBinaryStream(&_mncellNameMap, stream);
			cellNameMap = std::move(_mncellNameMap);
		}
		return true;

	case 0x68879477: //PobShipObject.cells
		{
			VectorMap<unsigned int, ManagedReference<CellObjectPOD* > > _mncells;
			TypeInfo<VectorMap<unsigned int, ManagedReference<CellObjectPOD* > > >::parseFromBinaryStream(&_mncells, stream);
			cells = std::move(_mncells);
		}
		return true;

	case 0x8be83e7e: //PobShipObject.launchPoints
		{
			PlayerLaunchPoints _mnlaunchPoints;
			TypeInfo<PlayerLaunchPoints >::parseFromBinaryStream(&_mnlaunchPoints, stream);
			launchPoints = std::move(_mnlaunchPoints);
		}
		return true;

	case 0x32a75560: //PobShipObject.shipPermissionList
		{
			ShipPermissionList _mnshipPermissionList;
			TypeInfo<ShipPermissionList >::parseFromBinaryStream(&_mnshipPermissionList, stream);
			shipPermissionList = std::move(_mnshipPermissionList);
		}
		return true;

	case 0xc567bea5: //PobShipObject.shipLootBox
		{
			ManagedReference<SceneObjectPOD* > _mnshipLootBox;
			TypeInfo<ManagedReference<SceneObjectPOD* > >::parseFromBinaryStream(&_mnshipLootBox, stream);
			shipLootBox = std::move(_mnshipLootBox);
		}
		return true;

	case 0xadbcec4e: //PobShipObject.sparkLocations
		{
			DamageSparkLocations _mnsparkLocations;
			TypeInfo<DamageSparkLocations >::parseFromBinaryStream(&_mnsparkLocations, stream);
			sparkLocations = std::move(_mnsparkLocations);
		}
		return true;

	case 0x764ecee0: //PobShipObject.plasmaAlarms
		{
			Vector<unsigned long long> _mnplasmaAlarms;
			TypeInfo<Vector<unsigned long long> >::parseFromBinaryStream(&_mnplasmaAlarms, stream);
			plasmaAlarms = std::move(_mnplasmaAlarms);
		}
		return true;

	case 0xde1ecd3b: //PobShipObject.interiorComponents
		{
			Vector<ManagedReference<ShipInteriorComponentPOD* > > _mninteriorComponents;
			TypeInfo<Vector<ManagedReference<ShipInteriorComponentPOD* > > >::parseFromBinaryStream(&_mninteriorComponents, stream);
			interiorComponents = std::move(_mninteriorComponents);
		}
		return true;

	case 0xa5bba4bb: //PobShipObject.plasmaConduits
		{
			Vector<ManagedReference<ShipInteriorComponentPOD* > > _mnplasmaConduits;
			TypeInfo<Vector<ManagedReference<ShipInteriorComponentPOD* > > >::parseFromBinaryStream(&_mnplasmaConduits, stream);
			plasmaConduits = std::move(_mnplasmaConduits);
		}
		return true;

	case 0x1aa76560: //PobShipObject.damagedInteriorComponents
		{
			VectorMap<unsigned long long, int> _mndamagedInteriorComponents;
			TypeInfo<VectorMap<unsigned long long, int> >::parseFromBinaryStream(&_mndamagedInteriorComponents, stream);
			damagedInteriorComponents = std::move(_mndamagedInteriorComponents);
		}
		return true;

	case 0x3903a703: //PobShipObject.plasmaConduitTypes
		{
			VectorMap<int, unsigned int> _mnplasmaConduitTypes;
			TypeInfo<VectorMap<int, unsigned int> >::parseFromBinaryStream(&_mnplasmaConduitTypes, stream);
			plasmaConduitTypes = std::move(_mnplasmaConduitTypes);
		}
		return true;

	case 0x961f37b: //PobShipObject.componentDamageVariables
		{
			VectorMap<uint32, float > _mncomponentDamageVariables;
			TypeInfo<VectorMap<uint32, float > >::parseFromBinaryStream(&_mncomponentDamageVariables, stream);
			componentDamageVariables = std::move(_mncomponentDamageVariables);
		}
		return true;

	}

	return false;
}

void PobShipObjectPOD::readObject(ObjectInputStream* stream) {
	uint16 _varCount = stream->readShort();
	for (int i = 0; i < _varCount; ++i) {
		uint32 _nameHashCode;
		TypeInfo<uint32>::parseFromBinaryStream(&_nameHashCode, stream);

		uint32 _varSize = stream->readInt();

		int _currentOffset = stream->getOffset();

		if(PobShipObjectPOD::readObjectMember(stream, _nameHashCode)) {
		}

		stream->setOffset(_currentOffset + _varSize);
	}

}

void PobShipObjectPOD::writeObjectCompact(ObjectOutputStream* stream) {
	ShipObjectPOD::writeObjectCompact(stream);

	TypeInfo<VectorMap<String, ManagedReference<CellObjectPOD* > > >::toBinaryStream(&cellNameMap.value(), stream);

	TypeInfo<VectorMap<unsigned int, ManagedReference<CellObjectPOD* > > >::toBinaryStream(&cells.value(), stream);

	TypeInfo<PlayerLaunchPoints >::toBinaryStream(&launchPoints.value(), stream);

	TypeInfo<ShipPermissionList >::toBinaryStream(&shipPermissionList.value(), stream);

	TypeInfo<ManagedReference<SceneObjectPOD* > >::toBinaryStream(&shipLootBox.value(), stream);

	TypeInfo<DamageSparkLocations >::toBinaryStream(&sparkLocations.value(), stream);

	TypeInfo<Vector<unsigned long long> >::toBinaryStream(&plasmaAlarms.value(), stream);

	TypeInfo<Vector<ManagedReference<ShipInteriorComponentPOD* > > >::toBinaryStream(&interiorComponents.value(), stream);

	TypeInfo<Vector<ManagedReference<ShipInteriorComponentPOD* > > >::toBinaryStream(&plasmaConduits.value(), stream);

	TypeInfo<VectorMap<unsigned long long, int> >::toBinaryStream(&damagedInteriorComponents.value(), stream);

	TypeInfo<VectorMap<int, unsigned int> >::toBinaryStream(&plasmaConduitTypes.value(), stream);

	TypeInfo<VectorMap<uint32, float > >::toBinaryStream(&componentDamageVariables.value(), stream);


}

